// mamba2_gated_norm.cu — device gated RMSNorm for the Mamba-2 (SSD) layer.
//
// WHY: after the SSD scan (mamba2_ssd_scan.cu) emits the raw `y` [d_inner], the HF
// `MambaRMSNormGated` (gate-FIRST) is applied to it:
//     tmp   = y * silu(z)                          (silu(z) = z * sigmoid(z))
//     ms    = mean(tmp²)  over d_inner
//     inv   = 1 / sqrt(ms + eps)
//     y_out = tmp * inv * norm_w
// Today that runs on the HOST after a dtoh(y) — the per-layer dtoh(y)/htod(x)/sync
// ping-pong the profiler measured as the dominant SSD_STEP cost (59% of the token).
// This kernel does the norm ON-DEVICE so the scan output `y` never leaves VRAM: the
// normed result stays resident to feed the resident out_proj GEMV directly.
//
// NUMERICS: fp32, matching the CPU f32 gated-norm exactly EXCEPT the reduction of
// mean(tmp²) is a parallel block-reduce (associativity differs from the host's
// left-to-right sum by a few ULP). The gated-norm is NOT the argmax-chaotic part of
// the forward (it already ran f32 on the host), so f32 + parallel reduce is within
// the parity gate. `1/sqrtf` (not the approximate `rsqrtf`) matches the CPU
// `1.0 / (ms+eps).sqrt()` to the last bit of the intrinsic.
//
// LAUNCH: ONE BLOCK (d_inner = 8192 fits a single block's strided sweep). block_dim
// MUST be a power of two (the tree reduction assumes it); the Rust caller uses 256.
// shared_mem = block_dim * sizeof(float) for the reduction scratch. 4 ptrs + 1 int +
// 1 float = 6 launch args (well under cudarc's 12-arg LaunchAsync cap). Gated by
// MESH_GPU_SSM_FUSED=1 on the Rust side; build.rs compiles it under the `cuda` feature.

extern "C" __global__ void mamba2_gated_norm(
    const float* __restrict__ y_in,   // [d_inner] raw scan output (resident mamba_y)
    const float* __restrict__ z,      // [d_inner] gate (silu applied here)
    const float* __restrict__ norm_w, // [d_inner] learnable gamma
    float* __restrict__ y_out,        // [d_inner] normed output (resident, distinct buffer)
    int d_inner,
    float eps)
{
    extern __shared__ float red[]; // [blockDim.x] reduction scratch
    const int tid = threadIdx.x;
    const int nthreads = blockDim.x;

    // Pass 1: tmp = y_in * silu(z); stash tmp in y_out; accumulate Σ tmp² locally.
    // silu(z) = z * sigmoid(z) = z / (1 + exp(-z)) — matches the CPU `z*sigmoid(z)`.
    float local = 0.0f;
    for (int i = tid; i < d_inner; i += nthreads) {
        const float zv  = z[i];
        const float sig = 1.0f / (1.0f + expf(-zv));
        const float tmp = y_in[i] * (zv * sig);
        y_out[i] = tmp; // reuse y_out as tmp scratch (rescaled in pass 2)
        local += tmp * tmp;
    }
    red[tid] = local;
    __syncthreads();

    // Block tree-reduce Σ tmp² (blockDim.x is a power of two).
    for (int s = nthreads >> 1; s > 0; s >>= 1) {
        if (tid < s) {
            red[tid] += red[tid + s];
        }
        __syncthreads();
    }

    // After the loop's final __syncthreads() every thread sees the total in red[0].
    const float ms  = red[0] / (float)d_inner;
    const float inv = 1.0f / sqrtf(ms + eps); // precise (not rsqrtf) → CPU-matching

    // Pass 2: y_out = tmp * inv * norm_w. Each thread rescales only the indices it
    // wrote in pass 1, so there is no cross-thread dependency on y_out here.
    for (int i = tid; i < d_inner; i += nthreads) {
        y_out[i] = y_out[i] * inv * norm_w[i];
    }
}
